import * as color from '@heroku/heroku-cli-util/color';
export function displayCIDR(cidr) {
    return cidr?.join(', ') ?? '';
}
export function displayVPNStatus(s) {
    switch (s) {
        case 'UP':
        case 'available': {
            return `${color.success(s)}`;
        }
        case 'pending':
        case 'provisioning':
        case 'deprovisioning': {
            return `${color.info(s)}`;
        }
        case 'DOWN':
        case 'deleting':
        case 'deleted': {
            return `${color.failure(s)}`;
        }
        default: {
            return s;
        }
    }
}
export function hostStatus(s) {
    switch (s) {
        case 'available': {
            return `${color.success(s)}`;
        }
        case 'under-assessment': {
            return `${color.info(s)}`;
        }
        case 'permanent-failure':
        case 'released-permanent-failure': {
            return `${color.failure(s)}`;
        }
        case 'released': {
            return `${color.gray(s)}`;
        }
        default: {
            return s;
        }
    }
}
export function peeringStatus(s) {
    switch (s) {
        case 'active': {
            return `${color.success(s)}`;
        }
        case 'pending-acceptance':
        case 'provisioning': {
            return `${color.info(s)}`;
        }
        case 'expired':
        case 'failed':
        case 'deleted':
        case 'rejected': {
            return `${color.failure(s)}`;
        }
        default: {
            return s;
        }
    }
}
